document.addEventListener("DOMContentLoaded",()=>{"use strict";const e=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&e.target.classList.add("is-visible")})},{root:null,rootMargin:"0px",threshold:.15});document.querySelectorAll(".glass-card, .service-item, .metric-card, .work-item, .section-header, h1, h2, .fade-up").forEach((t,s)=>{t.classList.contains("fade-up")||t.classList.add("fade-up"),t.style.transitionDelay=s%4*.1+"s",e.observe(t)});document.querySelectorAll("form").forEach(e=>{e.querySelectorAll("input, textarea").forEach(e=>{e.addEventListener("blur",()=>{e.checkValidity()?(e.classList.remove("invalid"),e.classList.add("valid")):(e.classList.remove("valid"),e.classList.add("invalid"))})})});(()=>{const e=document.createElement("div");e.style="position:fixed; top:0; left:0; width:100%; height:3px; z-index:2000; background:transparent;";const t=document.createElement("div");t.style="width:0%; height:100%; background:var(--c-accent); transition: width 0.1s;",e.appendChild(t),document.body.appendChild(e),window.addEventListener("scroll",()=>{const e=(window.scrollY||document.documentElement.scrollTop)/(document.documentElement.scrollHeight-document.documentElement.clientHeight)*100;t.style.width=e+"%"},{passive:!0})})()});
